using System;
using System.Collections.Generic;
using System.Linq;
using System.Threading;
using System.Threading.Tasks;

public static class Downloader
{
    public static async Task<string[]> DownloadAllAsync(
        IEnumerable<Uri> uris,
        Func<Uri, CancellationToken, Task<string>> fetch,
        CancellationToken cancellationToken)
    {
        var uriList = uris.ToList(); // Ensure we can access by index
        var fetchTasks = new Task<string>[uriList.Count];

        for (int i = 0; i < uriList.Count; i++)
        {
            int index = i; // Capture the index for the closure
            fetchTasks[index] = Task.Run(() => fetch(uriList[index], cancellationToken), cancellationToken);
        }

        try
        {
            // Await all tasks and return the results in order
            return await Task.WhenAll(fetchTasks).ConfigureAwait(false);
        }
        catch (OperationCanceledException)
        {
            // Ensures correct behavior if the operation is canceled
            throw;
        }
    }
}

