using System;
using System.Collections.Generic;
using System.Linq;
using System.Threading;
using System.Threading.Tasks;

public static class Downloader
{
    public static async Task<string[]> DownloadAllAsync(
        IEnumerable<Uri> uris,
        Func<Uri, CancellationToken, Task<string>> fetch,
        CancellationToken cancellationToken)
    {
        if (uris == null) throw new ArgumentNullException(nameof(uris));
        if (fetch == null) throw new ArgumentNullException(nameof(fetch));

        var tasks = uris.Select(uri => fetch(uri, cancellationToken)).ToArray();

        try
        {
            return await Task.WhenAll(tasks).ConfigureAwait(false);
        }
        catch (OperationCanceledException) when (cancellationToken.IsCancellationRequested)
        {
            throw;
        }
    }
}

using System.Threading.Channels;
using System.Threading.Tasks;

static class Pipeline
{
    public static async Task<long> ProduceConsumeSumAsync(int count)
    {
        if (count == 0)
        {
            return 0;
        }

        var channel = Channel.CreateBounded<int>(new BoundedChannelOptions(100)
        {
            SingleWriter = true,
            SingleReader = true
        });

        var writer = channel.Writer;
        var reader = channel.Reader;

        var producer = Task.Run(async () =>
        {
            for (int i = 0; i < count; i++)
            {
                await writer.WriteAsync(i);
            }
            writer.Complete();
        });

        long sum = 0;
        var consumer = Task.Run(async () =>
        {
            await foreach (var item in reader.ReadAllAsync())
            {
                sum += item;
            }
        });

        await Task.WhenAll(producer, consumer);
        return sum;
    }
}

