        foreach (var ch in text)
        {
            if (char.IsWhiteSpace(ch))
            {
                if (inWord)
                {
                    wordCount++;
                    inWord = false;
                }
            }
            else
            {
                inWord = true;
            }
        }

        if (inWord)
