using System;

public static class SpanParser
{
    public static int SumCsvInts(ReadOnlySpan<char> csv)
    {
        int sum = 0;
        int start = 0;

        for (int i = 0; i <= csv.Length; i++)
        {
            if (i == csv.Length || csv[i] == ',')
            {
                if (i > start)
                {
                    sum += int.Parse(csv[start..i]);
                }
                start = i + 1;
            }
        }

        return sum;
    }
}

